import{_ as t,c as o,o as r,ae as n}from"./chunks/framework.B7Y1jjX-.js";const m=JSON.parse('{"title":"组件结构","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/库/React/1Describing the UI/7组件结构.md","filePath":"generated-notes/前端/库/React/1Describing the UI/7组件结构.md"}'),a={name:"generated-notes/前端/库/React/1Describing the UI/7组件结构.md"};function s(d,e,c,i,p,h){return r(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="组件结构" tabindex="-1">组件结构 <a class="header-anchor" href="#组件结构" aria-label="Permalink to &quot;组件结构&quot;">​</a></h1><h2 id="the-render-tree" tabindex="-1">The Render Tree <a class="header-anchor" href="#the-render-tree" aria-label="Permalink to &quot;The Render Tree&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251206150605.png">查看图片：Pasted image 20251206150605.png</a></p><p>From the example app, we can construct the above render tree.</p><p>The tree is composed of nodes, each of which represents a component. <code>App</code>, <code>FancyText</code>, <code>Copyright</code>, to name a few, are all nodes in our tree.</p><p>The root node in a React render tree is the <a href="https://react.dev/learn/importing-and-exporting-components#the-root-component-file" target="_blank" rel="noreferrer">root component</a> of the app. In this case, the root component is <code>App</code> and it is the first component React renders. Each arrow in the tree points from a parent component to a child component.</p><h2 id="the-module-dependency-tree" tabindex="-1">The Module Dependency Tree <a class="header-anchor" href="#the-module-dependency-tree" aria-label="Permalink to &quot;The Module Dependency Tree&quot;">​</a></h2><p>The root node of the tree is the root module, also known as the entrypoint file. It often is the module that contains the root component.</p><p>Comparing to the render tree of the same app, there are similar structures but some notable differences:</p><ul><li>The nodes that make-up the tree represent modules, not components.</li><li>Non-component modules, like <code>inspirations.js</code>, are also represented in this tree. The render tree only encapsulates components.</li><li><code>Copyright.js</code> appears under <code>App.js</code> but in the render tree, <code>Copyright</code>, the component, appears as a child of <code>InspirationGenerator</code>. This is because <code>InspirationGenerator</code> accepts JSX as <a href="https://react.dev/learn/passing-props-to-a-component#passing-jsx-as-children" target="_blank" rel="noreferrer">children props</a>, so it renders <code>Copyright</code> as a child component but does not import the module.</li></ul>',10)])])}const u=t(a,[["render",s]]);export{m as __pageData,u as default};
